challenge.solution:
import { useState } from 'react';

function Counter() {
  const [count, setCount] = useState(0);

  return (
    <div>
      <p>Contagem: {count}</p>
      <button onClick={() => setCount(c => c + 1)}>+1</button>
      <button onClick={() => setCount(0)}>Resetar</button>
    </div>
  );
}

import { render, screen, fireEvent } from '@testing-library/react';

test('contador começa em 0', () => {
  render(<Counter />);
  expect(screen.getByText('Contagem: 0')).toBeInTheDocument();
});

test('incrementa ao clicar em +1', () => {
  render(<Counter />);
  fireEvent.click(screen.getByText('+1'));
  expect(screen.getByText('Contagem: 1')).toBeInTheDocument();
});

test('reseta ao clicar em Resetar', () => {
  render(<Counter />);
  fireEvent.click(screen.getByText('+1'));
  fireEvent.click(screen.getByText('Resetar'));
  expect(screen.getByText('Contagem: 0')).toBeInTheDocument();
});
